import { Link, useNavigate } from 'react-router-dom';

function Navbar() {
  const navigate = useNavigate();

  // Get user and token from localStorage
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user'));

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  const navStyle = {
    background: 'linear-gradient(to right, #3b82f6, #8b5cf6, #ec4899)',
    boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
    position: 'sticky',
    top: 0,
    zIndex: 50,
  };

  const containerStyle = {
    maxWidth: '60px',
    margin: '0 auto',
    padding: '0 1rem',
  };

  const flexStyle = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    height: '5rem',
  };

  const logoStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '0.75rem',
    textDecoration: 'none',
  };

  const logoTextStyle = {
    fontSize: '1.5rem',
    fontWeight: 'bold',
    color: 'white',
  };

  const menuStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '1.5rem',
  };

  const linkStyle = {
    color: 'white',
    textDecoration: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '0.5rem',
    fontWeight: '500',
    transition: 'all 0.3s',
  };

  const buttonStyle = {
    background: 'white',
    color: '#8b5cf6',
    padding: '0.5rem 1.5rem',
    borderRadius: '9999px',
    border: 'none',
    fontWeight: '600',
    cursor: 'pointer',
    transition: 'all 0.3s',
  };

  return (
    <nav style={navStyle}>
      <div style={containerStyle}>
        <div style={flexStyle}>
          <Link to="/" style={logoStyle}>
            <span style={{ fontSize: '2rem' }}>🎉</span>
            <span style={logoTextStyle}>EventHub</span>
          </Link>

          <div style={menuStyle}>
            <Link to="/" style={linkStyle}>Home</Link>

            {token ? (
              <>
                <Link to="/my-bookings" style={linkStyle}>My Bookings</Link>

                {user?.role === 'admin' && (
                  <Link to="/admin" style={linkStyle}>Admin</Link>
                )}

                <span style={{ ...linkStyle, cursor: 'default' }}>
                  {user?.name}
                </span>

                <button
                  onClick={handleLogout}
                  style={{ ...buttonStyle, background: '#ef4444', color: 'white' }}
                >
                  Logout
                </button>
              </>
            ) : (
              <>
                <Link to="/login" style={linkStyle}>Login</Link>
                <Link to="/register">
                  <button style={buttonStyle}>Sign Up Free</button>
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
